SELECT summary_date
FROM daily_summaries
WHERE summary_id = 1;

SELECT AVG(high_temperature) AS average_high_temperature
FROM daily_summaries
WHERE summary_date = '2023-05-02';

SELECT summary
FROM daily_summaries
WHERE station_id = 1 AND summary_date BETWEEN '2023-01-01' AND '2023-01-31';

SELECT summary_date, SUM(total_precipitation) AS total_daily_precipitation
FROM daily_summaries
GROUP BY summary_date;
